import math

def theoretical_speedup(alpha: float, k: int, r: float) -> float:
    """
    Expected speedup from speculative decoding.
    alpha: per-token acceptance rate (0-1)
    k:     number of draft tokens per step
    r:     T_draft / T_target  (latency ratio)
    """
    if alpha >= 1.0:
        # Perfect acceptance: speedup = (k+1) / (kr + 1)
        return (k + 1) / (k * r + 1)
    expected_accepted = (1 - alpha ** (k + 1)) / (1 - alpha)
    return expected_accepted / (k * r + 1)


def optimal_k(alpha: float, r: float, k_range=range(1, 16)) -> tuple[int, float]:
    """Find k that maximises theoretical speedup."""
    best_k, best_speedup = 1, 0.0
    for k in k_range:
        s = theoretical_speedup(alpha, k, r)
        if s > best_speedup:
            best_speedup, best_k = s, k
    return best_k, best_speedup


# Print the grid for typical alpha and r values
print(f"{'alpha':>6} {'r':>6} {'best_k':>8} {'speedup':>9}")
for alpha in [0.60, 0.70, 0.80, 0.85, 0.90, 0.95]:
    for r in [0.05, 0.10, 0.15]:
        k, s = optimal_k(alpha, r)
        print(f"{alpha:6.2f} {r:6.2f} {k:8d} {s:9.2f}x")
    print()
